import{_ as o,o as t,c as a,a5 as s}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"UPS 持续提高路线（Continuous Learning Path）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"UPS 持续提高路线（Continuous Learning Path）","tags":["power-electronics"],"status":"learning","summary":"这份路线用于承接 `roadmap/30-day-plan.md` 之后的长期训练。30 天计划只负责打基础，不代表课程到第 30 天结束。后续仍然按“一个概念讲清楚 + 一个仿真任务 + 复盘问题 + 导师问题”的节奏推进。"},"headers":[],"relativePath":"content/power/roadmap/continuous-learning-path.md","filePath":"content/power/roadmap/continuous-learning-path.md","lastUpdated":null}'),l={name:"content/power/roadmap/continuous-learning-path.md"};function c(r,e,i,n,p,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="ups-持续提高路线-continuous-learning-path" tabindex="-1">UPS 持续提高路线（Continuous Learning Path） <a class="header-anchor" href="#ups-持续提高路线-continuous-learning-path" aria-label="Permalink to &quot;UPS 持续提高路线（Continuous Learning Path）&quot;">​</a></h1><p>这份路线用于承接 <code>roadmap/30-day-plan.md</code> 之后的长期训练。30 天计划只负责打基础，不代表课程到第 30 天结束。后续仍然按“一个概念讲清楚 + 一个仿真任务 + 复盘问题 + 导师问题”的节奏推进。</p><h2 id="总目标" tabindex="-1">总目标 <a class="header-anchor" href="#总目标" aria-label="Permalink to &quot;总目标&quot;">​</a></h2><p>长期目标保持三条主线：</p><ul><li>能自行推导 UPS 相关拓扑的基本工作原理，包括 Boost、功率因数校正（power factor correction / PFC）、LLC 谐振变换器（inductor-inductor-capacitor resonant converter / LLC）、维也纳整流器（Vienna rectifier）和三电平逆变器（three-level inverter）。</li><li>能较顺畅阅读带有部分注释的完整 C 语言工程代码，理解控制中断、采样、脉宽调制（pulse-width modulation / PWM）、保护、状态机、通信和参数管理之间的关系。</li><li>能自行实现一个具备基本功能的简化 UPS 软件骨架，包括启动、采样、控制、保护判断、模式切换、故障锁存、通信接口和日志记录。</li></ul><h2 id="阶段-a-系统级-ups-软件骨架" tabindex="-1">阶段 A：系统级 UPS 软件骨架 <a class="header-anchor" href="#阶段-a-系统级-ups-软件骨架" aria-label="Permalink to &quot;阶段 A：系统级 UPS 软件骨架&quot;">​</a></h2><p>目标：把 Boost、PFC、锁相环（phase-locked loop / PLL）、逆变器、旁路、保护和通信串成一个可阅读的软件结构。</p><p>建议专题：</p><ul><li>UPS 模式状态机（UPS mode state machine）：市电模式、电池模式、旁路模式、故障模式；已开始用 <code>lessons/0024-ups-mode-state-machine.html</code> 和 <code>simulations/python/ups_mode_state_machine.py</code> 建立入门模型。</li><li>简化 UPS C 固件骨架（UPS C firmware skeleton）：已开始用 <code>lessons/0025-ups-c-firmware-skeleton.html</code> 和 <code>projects/03-ups-c-firmware-skeleton</code> 把模式状态机迁移到可编译、可运行、可提问的 C 工程结构。</li><li>UPS C 参数表（UPS C parameter table）：已开始用 <code>lessons/0026-ups-c-parameter-table.html</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/parameters.c</code> 训练阈值、保持时间和控制周期的集中阅读方式。</li><li>UPS 保护标志（UPS protection flags）：已开始用 <code>lessons/0027-ups-c-protection-flags.html</code>、<code>simulations/python/ups_protection_flags.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/protection.c</code> 训练“采样值 + 参数表 -&gt; 保护标志”的阅读路径。</li><li>保护去抖与故障锁存（protection debounce and fault latch）：已开始用 <code>lessons/0028-ups-fault-latch-debounce.html</code>、<code>simulations/python/ups_fault_latch_debounce.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/fault_latch.c</code> 训练“瞬时标志 -&gt; 确认故障 -&gt; 锁存 -&gt; 安全复位”的阅读路径。</li><li>系统故障闭环（system fault closure）：已开始用 <code>lessons/0029-ups-system-fault-closure.html</code>、<code>simulations/python/ups_system_fault_closure.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/system_step.c</code> 训练“故障锁存 -&gt; 模式强制 -&gt; 输出关闭 -&gt; 安全复位”的系统仲裁路径。</li><li>故障码与故障日志（fault code and fault log）：已开始用 <code>lessons/0030-ups-fault-code-logging.html</code>、<code>simulations/python/ups_fault_code_logging.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/fault_log.c</code> 训练“故障发生 -&gt; 编码 -&gt; 记录时间戳和触发源 -&gt; 导师复盘”的阅读路径。</li><li>遥测通信帧（telemetry communication frame）：已开始用 <code>lessons/0031-ups-telemetry-frame.html</code>、<code>simulations/python/ups_telemetry_frame.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/telemetry.c</code> 训练“状态机/故障日志/输出许可 -&gt; 外部可观察上报”的阅读路径。</li><li>命令解析与安全门控（command parsing and safety gating）：已开始用 <code>lessons/0032-ups-command-parser.html</code>、<code>simulations/python/ups_command_parser.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/command_parser.c</code> 训练“外部命令 -&gt; 内部意图 -&gt; 安全条件允许后执行”的阅读路径。</li><li>命令响应与拒绝原因（command response and reject reason）：已开始用 <code>lessons/0033-ups-command-response.html</code>、<code>simulations/python/ups_command_response.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/command_response.c</code> 训练“命令处理结果 -&gt; 响应码 -&gt; 拒绝原因”的阅读路径。</li><li>参数访问边界（parameter access boundary）：已开始用 <code>lessons/0034-ups-parameter-access.html</code>、<code>simulations/python/ups_parameter_access.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/parameter_access.c</code> 训练“参数表 -&gt; 只读/可写策略 -&gt; 范围校验 -&gt; 写入结果”的阅读路径。</li><li>参数保存与默认值恢复（parameter storage and default restore）：已开始用 <code>lessons/0035-ups-parameter-storage.html</code>、<code>simulations/python/ups_parameter_storage.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/parameter_storage.c</code> 训练“参数快照 -&gt; NVM 记录 -&gt; 校验和 -&gt; 默认值恢复”的阅读路径。</li><li>参数保存触发策略（parameter save scheduler）：已开始用 <code>lessons/0036-ups-parameter-save-scheduler.html</code>、<code>simulations/python/ups_parameter_save_scheduler.py</code> 和 <code>projects/03-ups-c-firmware-skeleton/src/parameter_save_scheduler.c</code> 训练“参数写入 -&gt; 脏标志 -&gt; 延时提交 -&gt; 合并保存”的阅读路径。</li><li>直流母线协调（DC bus coordination）：PFC、DC-DC、电池和逆变器之间的功率平衡。</li><li>旁路同步与切换（bypass synchronization and transfer）：电压、频率、相位窗口和保持时间。</li><li>简化 C 工程骨架后续扩展：启动、采样、控制、保护、故障锁存、通信接口、参数表和日志。</li></ul><h2 id="阶段-b-高功率拓扑推导" tabindex="-1">阶段 B：高功率拓扑推导 <a class="header-anchor" href="#阶段-b-高功率拓扑推导" aria-label="Permalink to &quot;阶段 B：高功率拓扑推导&quot;">​</a></h2><p>目标：不只会看结论，而是能自己从开关状态、能量流和平均模型推导核心关系。</p><p>建议专题：</p><ul><li>维也纳整流器（Vienna rectifier）：三相输入电流、三电平开关状态、中点电压平衡。</li><li>三电平逆变器（three-level inverter）：中点钳位（neutral-point clamped / NPC）、空间矢量调制（space vector pulse-width modulation / SVPWM）、中点平衡。</li><li>LLC 谐振变换器（inductor-inductor-capacitor resonant converter / LLC）：谐振腔频率响应、软开关、轻载跳频或脉冲控制边界。</li><li>双向 DC-DC 变换器（bidirectional DC-DC converter）：电池充放电、限流、预充和方向切换。</li></ul><h2 id="阶段-c-仿真能力升级" tabindex="-1">阶段 C：仿真能力升级 <a class="header-anchor" href="#阶段-c-仿真能力升级" aria-label="Permalink to &quot;阶段 C：仿真能力升级&quot;">​</a></h2><p>目标：从单脚本波形观察，升级到可复现实验、参数扫描和模型对比。</p><p>建议专题：</p><ul><li>Python 参数扫描：自动生成多组图，文件名和图内参数框说明条件。</li><li>MATLAB/Simulink 平均模型：先建平均模型，再逐步加入开关模型。</li><li>控制器离散化：连续 PI/PR 到离散实现，含限幅、抗积分饱和和采样延迟。</li><li>故障注入：过压、欠压、过流、PLL 失锁、旁路相位跳变。</li></ul><h2 id="阶段-d-资料和视频阅读方式" tabindex="-1">阶段 D：资料和视频阅读方式 <a class="header-anchor" href="#阶段-d-资料和视频阅读方式" aria-label="Permalink to &quot;阶段 D：资料和视频阅读方式&quot;">​</a></h2><p>目标：逐步提高阅读英文资料和工程资料的能力，但仍坚持中文主讲。</p><p>使用规则：</p><ul><li>先用中文写“这份资料解决什么问题、我只看哪几页或哪几节”。</li><li>把关键术语整理成中英对照，例如锁相环（phase-locked loop / PLL）和脉宽调制（pulse-width modulation / PWM）。</li><li>看视频时必须产出一张结构图、一段推导或一个仿真复现，不能只记标题。</li><li>推荐资料必须记录到 <code>RESOURCES.md</code>，并标注适合的学习阶段、主题和可信度。</li></ul><h2 id="阶段-e-导师复盘闭环" tabindex="-1">阶段 E：导师复盘闭环 <a class="header-anchor" href="#阶段-e-导师复盘闭环" aria-label="Permalink to &quot;阶段 E：导师复盘闭环&quot;">​</a></h2><p>每次问导师前，至少准备一个具体产物：</p><ul><li>一张仿真图，例如 <code>simulations/results/single_phase_bypass_sync_transfer.png</code>。</li><li>一段代码片段，例如控制 ISR、状态机或保护判断。</li><li>一个参数表，例如同步窗口、保护阈值或采样频率。</li><li>一个明确卡点，例如“为什么相位窗口满足后还要保持 30 ms”。</li></ul><p>导师反馈不直接写入公司内部参数或项目细节，只记录通用原则、公开知识和自己的理解修正。</p>',25)])])}const h=o(l,[["render",c]]);export{m as __pageData,h as default};
